#include<bits/stdc++.h>
using namespace std;
int n;
int s[2000010];
struct node
{
    int a,b,id;
    bool operator<(const node&y)const
    {
        return b<y.b;
    }
}b[2000010];
int a[2000010],ans[2000010],lst[2000010];
int lowbit(int x)
{
    return x&-x;
}
void update(int x,int k)
{
    for(int i=x;i<=2000000;i+=lowbit(i))
    {
        s[i]+=k;
    }
}
int sum(int x)
{
    int ans=0;
    for(int i=x;i;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int q;
    scanf("%d",&q);
    for(int i=1;i<=q;i++)
    {
        scanf("%d%d",&b[i].a,&b[i].b);
        b[i].id=i;
    }
    sort(b+1,b+1+q);
    int r=1;
    for(int i=1;i<=q;i++)
    {
        while(r<=b[i].b)
        {
            if(lst[a[r]]!=0)
            {
                update(lst[a[r]],-1);
            }
            lst[a[r]]=r;
            update(r,1);
            r++;
        }
        ans[b[i].id]=sum(b[i].b)-sum(b[i].a-1);
    }
    for(int i=1;i<=q;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
